import{_ as a,o as t,c as s,ae as i}from"./chunks/framework.EHGTsUvI.js";const h=JSON.parse('{"title":"Using git tags","description":"","frontmatter":{"headerImage":"https://images.unsplash.com/photo-1618401479427-c8ef9465fbe1?ixlib=rb-1.2.1&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1143&q=80","title":"Using git tags","published":true,"date":"2021-12-07T15:40:00.000Z","excerpt":"Basic usage of git tags with GitHub, creating, pushing, deleting, and releases."},"headers":[],"relativePath":"blog/git_tags.md","filePath":"blog/git_tags.md"}'),o={name:"blog/git_tags.md"};function n(r,e,c,l,d,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="intro" tabindex="-1">Intro <a class="header-anchor" href="#intro" aria-label="Permalink to &quot;Intro&quot;">​</a></h1><p>Git tags are a useful mechanism to differentiate certain commits. A tag is tied to one and only one commit, but symbolizes that point in the history of the repository.</p><p>Tags are frequently used to represent new releases, but GitHub actually has its own structure for this: &quot;Releases&quot;.</p><h2 id="basic-commands" tabindex="-1">Basic commands <a class="header-anchor" href="#basic-commands" aria-label="Permalink to &quot;Basic commands&quot;">​</a></h2><p>Create a new tag <code>git tag 0.0.1</code>.</p><p>Push the new tag <code>git push origin --tags</code>.</p><p>Delete a local tag <code>git tag -d 0.0.1</code>.</p><p>Delete a remote tag <code>git push --delete origin 0.0.1</code>.</p><p>List tags <code>git tag -l</code>.</p><h2 id="creating-a-release" tabindex="-1">Creating a release <a class="header-anchor" href="#creating-a-release" aria-label="Permalink to &quot;Creating a release&quot;">​</a></h2><p>From the GitHub interface, navigate to the code tab, here we can see the repo tags. If we enter &quot;tags&quot;, we navigate to a new view with &quot;Tags&quot; and &quot;Releases&quot;. Inside the releases tab, we have the option to create a new release based off a specific tag.</p><h2 id="uses" tabindex="-1">Uses <a class="header-anchor" href="#uses" aria-label="Permalink to &quot;Uses&quot;">​</a></h2><p>It&#39;s always nice to have a structured and organized project, clearly indicating new versions. But! The most interesting use I&#39;ve found for personal or small projects is combining releases with GitHub actions. We can choose to trigger a GitHub deploy action only when a new releases is created:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>on:</span></span>
<span class="line"><span>  release:</span></span>
<span class="line"><span>    types: [published]</span></span></code></pre></div>`,14)])])}const u=a(o,[["render",n]]);export{h as __pageData,u as default};
